import {
  CONTRACT_TYPE_META,
  DEFAULT_FRANCHISE_VARIANT,
  DEFAULT_WITHDRAWAL_VARIANT,
  type ContractType,
  type ContractVariant,
} from "./contract-types";

function escape(s: string): string {
  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

/* -------------------------------------------------------------------------
 * Smlouva o provozování provozovny (operation)
 * Manažer = BOServices (provider). Franšízant = klient. BOServices
 * provozuje provozovnu pro klienta - vede personál, sklad, tržby.
 * Hardcoded: odměna 30 000 Kč, fakturace 22. den, výpovědní doba 3 měsíce.
 * ------------------------------------------------------------------------- */
function operationHtml(): string {
  return `<h2>Smluvní strany</h2><p><strong>{{providerName}}</strong>, IČO: {{providerIco}}, DIČ: {{providerDic}}, se sídlem {{providerStreet}}, {{providerZip}} {{providerCity}}, zastoupená {{providerStatutory1Name}}, {{providerStatutory1Role}} (dále jen „<strong>Manažer</strong>“)</p><p>a</p><p><strong>{{clientName}}</strong>, IČO: {{clientIco}}, DIČ: {{clientDic}}, se sídlem {{clientStreet}}, {{clientZip}} {{clientCity}}{{clientRepresentationClause}}, e-mail: {{clientEmail}}, telefon: {{clientPhone}} (dále jen „<strong>Franšízant</strong>“)</p><p>Manažer a Franšízant společně dále jen „<strong>Smluvní strany</strong>“.</p><h2>1. Úvodní ustanovení</h2><ol><li><p>Manažer a Franšízant uzavřeli téhož dne franšízingovou smlouvu (dále jen „<strong>Franšízingová smlouva</strong>“), na jejímž základě je Franšízant oprávněn provozovat provozovnu na adrese <strong>{{provozovnaAddress}}</strong> (dále jen „<strong>Provozovna</strong>“). Franšízant je vlastníkem vybavení Provozovny.</p></li><li><p>Franšízant má zájem o zajištění provozování Provozovny Manažerem a Manažer má zájem o provozování Provozovny pro Franšízanta. Účelem této Smlouvy je úprava podmínek tohoto provozování.</p></li></ol><h2>2. Provoz a hospodaření Provozovny</h2><ol><li><p>Manažer zajistí plný provoz Provozovny jako její provozovatel ve smyslu zákona č. 455/1991 Sb., o živnostenském podnikání, a to na vlastní jméno a vlastní odpovědnost. Manažer zejména:</p><ol><li><p>zajišťuje personální obsazení Provozovny a vede mzdovou a personální agendu; pracovníci Provozovny jsou zaměstnanci Manažera,</p></li><li><p>plní povinnosti vyplývající z nájemní smlouvy k Provozovně,</p></li><li><p>vede skladové hospodářství (suroviny, zboží, spotřební materiál),</p></li><li><p>zabezpečuje a zpracovává přijaté hotovostní tržby,</p></li><li><p>vyplácí Franšízantovi tržby snížené o náklady dle této Smlouvy.</p></li></ol></li><li><p>Náklady vzniklé v souvislosti s provozem Provozovny (dále jen „<strong>Náklady</strong>“) hradí Manažer, a to buď z vlastních prostředků, nebo z prostředků v rámci přijatých hotovostních tržeb Provozovny. Za Náklady se považují zejména:</p><ol><li><p>náklady související s nájemní smlouvou (nájem, energie a služby spojené s nájmem, vybavení a další pravidelné platby pronajímateli),</p></li><li><p>osobní náklady zaměstnanců Provozovny (mzdy, odvody, benefity), jakož náklady na osoby dodávající prodejní službu (IČaři),</p></li><li><p>suroviny, zboží a spotřební materiál pořízený v souvislosti s provozem Provozovny,</p></li><li><p>pojištění Provozovny,</p></li><li><p>správní pokuty a jiné sankce uložené v souvislosti s provozem Provozovny,</p></li><li><p>náklady na obnovu vybavení provozovny a drobné investice.</p></li></ol></li><li><p>Manažer nejpozději do <strong>22. dne</strong> kalendářního měsíce následujícího po měsíci, za který se vyúčtování provádí, vyčíslí Náklady Provozovny a provede jejich fakturaci na Franšízanta s aplikací příslušné sazby DPH. Manažer má právo započíst svou pohledávku z titulu Nákladů fakturovaných dle tohoto článku Franšízantovi oproti svým závazkům vůči Franšízantovi.</p></li><li><p>Hotovostní tržby, které Manažer obdrží v souvislosti s Provozovnou, jsou ve vlastnictví Franšízanta, přičemž měsíční hotovostní tržby, v rozsahu, ve kterém nebyly použity k úhradě Nákladů, předá Manažer Franšízantovi hotovostním či bezhotovostním způsobem (dle volby Franšízanta) do <strong>22. dne</strong> měsíce následujícího po měsíci, kterého se dané hotovostní tržby týkají. Bezhotovostní tržby Provozovny se řídí režimem upraveným ve Franšízingové smlouvě.</p></li><li><p>Ve vztahu k hotovostním tržbám provádí Manažer jejich prostou správu. Manažer může tyto prostředky používat zejména v souvislosti s provozem Provozovny (např. při rozměňování hotovostních prostředků zákazníkům), pro účely úhrady Nákladů či úhradu pohledávek Manažera za Franšízantem.</p></li><li><p>Manažer je povinen na žádost Franšízanta předložit Franšízantovi podklady k vyúčtování (zejména doklady o tržbách, mzdové a nájemní náklady, faktury dodavatelů) v rozsahu nezbytném k ověření vyúčtování dle této Smlouvy.</p></li><li><p>Ustanovení tohoto článku je nutné vykládat tak, že úmyslem Smluvních stran je upravit práva a povinnosti způsobem, aby Franšízantovi byl vyplácen čistý zisk Provozovny (tj. tržby po odečtení Nákladů a Odměny) a zároveň, aby Franšízant nesl ztrátu Provozovny (pokud Náklady a Odměna budou převyšovat tržby).</p></li></ol><h2>3. Odměna Manažera</h2><ol><li><p>Za služby dle této Smlouvy náleží Manažerovi měsíční odměna ve výši <strong>30 000 Kč</strong> bez DPH (dále jen „<strong>Odměna</strong>“). Odměna náleží Manažerovi bez ohledu na to, zda Provozovna v daném měsíci dosáhla zisku nebo ztráty; Odměna je splatná 22. den měsíce následujícího po měsíci, za který se Odměna týká, a to na základě vystavené faktury.</p></li><li><p>K Odměně bude připočteno DPH v sazbě dle platných právních předpisů. Faktura bude vystavena v měně CZK, EUR nebo PLN, a to dle vhodnosti podle typu lokace a umístění Provozovny. Měnu fakturace určí Manažer písemným oznámením Franšízantovi, popřípadě ji Smluvní strany sjednají v dodatku k této Smlouvě. Není-li určeno jinak, je výchozí měnou fakturace CZK.</p></li><li><p>Manažer je oprávněn vždy jednou za kalendářní rok jednostranně zvýšit Odměnu o procentní přírůstek průměrného ročního indexu spotřebitelských cen za předchozí kalendářní rok, vyhlášený Českým statistickým úřadem. Takto zvýšená Odměna náleží Manažerovi zpětně od 1. ledna kalendářního roku, v němž Český statistický úřad tento údaj zveřejnil. K provedení tohoto zvýšení se nevyžaduje uzavření dodatku ke Smlouvě.</p></li><li><p>Pro případ prodlení s úhradou kteréhokoli peněžitého plnění dle této Smlouvy se Smluvní strana, která je v prodlení, zavazuje platit druhé Smluvní straně od prvního dne prodlení úroky z prodlení ve výši <strong>0,1 %</strong> z dlužné částky za každý započatý den prodlení.</p></li></ol><h2>4. Doba trvání a ukončení Smlouvy</h2><ol><li><p>Tato Smlouva se uzavírá na dobu neurčitou. Smlouva pozbývá platnosti a účinnosti dnem zániku Franšízingové smlouvy, ať už z jakéhokoli důvodu.</p></li><li><p>Každá ze Smluvních stran je oprávněna tuto Smlouvu vypovědět i bez uvedení důvodu s výpovědní dobou <strong>3 měsíce</strong>. Výpovědní doba počíná běžet prvním dnem kalendářního měsíce následujícího po měsíci, ve kterém byla písemná výpověď doručena druhé Smluvní straně.</p></li><li><p>Manažer je dále oprávněn tuto Smlouvu vypovědět s okamžitou účinností v případě, že Franšízant:</p><ol><li><p>je v prodlení s úhradou kteréhokoli peněžitého plnění dle této Smlouvy o více než 30 dnů,</p></li><li><p>poruší podstatným způsobem svůj závazek dle této Smlouvy a nezjedná nápravu ani ve lhůtě 7 dnů od písemné výzvy druhé Smluvní strany.</p></li></ol></li><li><p>Výpověď i odstoupení musí být učiněny písemně a doručeny druhé Smluvní straně. Výpověď i odstoupení se mají za doručené 3. pracovní den ode dne odeslání doporučenou poštou na adresu Smluvní strany v záhlaví, do datové schránky nebo na korespondenční adresu, pokud nebudou doručeny dříve.</p></li></ol><h2>5. Předání Provozovny při ukončení Smlouvy</h2><ol><li><p>Při ukončení této Smlouvy z jakéhokoli důvodu Manažer předá Provozovnu Franšízantovi (nebo jím určené osobě) na základě předávacího protokolu podepsaného Smluvními stranami, a to nejpozději do 3 pracovních dnů od skončení účinnosti této Smlouvy.</p></li><li><p>Předání zahrnuje zejména:</p><ol><li><p>inventuru skladu k poslednímu dni účinnosti Smlouvy s oceněním zboží a spotřebního materiálu,</p></li><li><p>předání hotovosti z pokladny Provozovny proti zápisu,</p></li><li><p>předání všech klíčů, přístupových karet a hesel k POS systému, kamerovému systému, internetovému bankovnictví dedikovanému Provozovně,</p></li><li><p>předání HACCP a obdobné provozní dokumentace,</p></li><li><p>předání evidence smluv s dodavateli souvisejících s provozem Provozovny.</p></li></ol></li><li><p>V případě prodlení Manažera s předáním Provozovny je Franšízant oprávněn na náklady Manažera zajistit předání náhradním způsobem (zejména zámečnickou službou, externí inventurou). Tím není dotčeno právo Franšízanta na náhradu škody.</p></li></ol><h2>6. Odpovědnost Manažera</h2><ol><li><p>Smluvní strany sjednávají, že celková výše náhrady škody, za níž Manažer odpovídá Franšízantovi v souvislosti s touto Smlouvou, je za jeden incident omezena částkou odpovídající <strong>jednonásobku měsíční Odměny</strong>. Manažer dále neodpovídá za nepřímou škodu, ušlý zisk a následné škody.</p></li></ol><h2>7. Závěrečná ustanovení</h2><ol><li><p>Tato Smlouva nabývá platnosti a účinnosti dnem jejího podpisu oběma Smluvními stranami.</p></li><li><p>Pro vyloučení všech pochybností Smluvní strany výslovně potvrzují, že tato Smlouva nezakládá společnost ve smyslu § 2716 a násl. zákona č. 89/2012 Sb., občanský zákoník, ani tiché společenství dle § 2747 a násl. téhož zákona. Smluvní strany rovněž výslovně potvrzují, že jsou podnikateli, uzavírají tuto Smlouvu při svém podnikání, a na tuto Smlouvu se neuplatní ustanovení § 1793 téhož zákona. Všechny faktury vystavené podle této Smlouvy jsou splatné 7. den od jejich vystavení, pokud není výslovně sjednáno jinak.</p></li><li><p>Tuto Smlouvu lze měnit a doplňovat pouze písemnou formou vzestupně číslovaných dodatků podepsaných oběma Smluvními stranami.</p></li><li><p>Je-li některé ustanovení této Smlouvy neplatné nebo neúčinné, ostatní zůstávají platná. Smluvní strany se zavazují nahradit takové ustanovení novým, které nejlépe odpovídá původnímu účelu.</p></li><li><p>Zaplacením kterékoli smluvní pokuty sjednané v této Smlouvě není dotčeno právo dotčené Smluvní strany na náhradu škody v plném rozsahu, a to i v rozsahu převyšujícím sjednanou smluvní pokutu.</p></li><li><p>Manažer je oprávněn tuto Smlouvu i bez souhlasu Franšízanta zčásti či zcela postoupit, přičemž postoupením se osvobozuje od svých povinností v rozsahu postoupení; Smluvní strany výslovně vylučují aplikaci § 1899 OZ.</p></li><li><p>Vybavení Provozovny je ke dni podpisu této Smlouvy uvedeno v Příloze č. 1, která je nedílnou součástí této Smlouvy.</p></li></ol><h2>Podpisy</h2><p>V {{place}} dne {{contractDate}}.</p><p>&nbsp;</p><p>__________________________<br><strong>{{providerStatutory1Name}}</strong><br>{{providerStatutory1Role}}<br>za Manažera: {{providerName}}</p><p>&nbsp;</p><p>V _________ dne ______________ .</p><p>&nbsp;</p><p>__________________________<br><strong>{{clientSignerName}}</strong><br>{{clientSignerRole}}<br>za Franšízanta: {{clientName}}</p><h2>Příloha č. 1 — Vybavení Provozovny</h2><p><em>Doplňte seznam vybavení (kuchyňské spotřebiče, nábytek, POS, kamerový systém, ...).</em></p>`;
}

/* -------------------------------------------------------------------------
 * Smlouva o spolupráci a podpoře při provozování provozovny (cooperation)
 * Manažer = BOServices (provider). Franšízant = klient. BOServices
 * poskytuje metodickou pomoc, regionální manažer, edukace.
 * Hardcoded: odměna 30 000 Kč, fakturace 15. den.
 * ------------------------------------------------------------------------- */
function cooperationHtml(): string {
  return `<h2>Smluvní strany</h2><p><strong>{{providerName}}</strong>, IČO: {{providerIco}}, DIČ: {{providerDic}}, se sídlem {{providerStreet}}, {{providerZip}} {{providerCity}}, zastoupená {{providerStatutory1Name}}, {{providerStatutory1Role}} (dále jen „<strong>Manažer</strong>“)</p><p>a</p><p><strong>{{clientName}}</strong>, IČO: {{clientIco}}, DIČ: {{clientDic}}, se sídlem {{clientStreet}}, {{clientZip}} {{clientCity}}{{clientRepresentationClause}}, e-mail: {{clientEmail}}, telefon: {{clientPhone}} (dále jen „<strong>Franšízant</strong>“)</p><p>Manažer a Franšízant společně dále jen „<strong>Smluvní strany</strong>“.</p><h2>1. Úvodní ustanovení, účel Smlouvy</h2><ol><li><p>Franšízant prohlašuje, že na základě franšízingové smlouvy je oprávněn provozovat provozovnu v rámci franšízingové sítě <strong>{{conceptName}}</strong> na adrese <strong>{{provozovnaAddress}}</strong> (dále jen „<strong>Provozovna</strong>“). Franšízant je vlastníkem vybavení Provozovny.</p></li><li><p>Franšízant je výhradním provozovatelem Provozovny ve smyslu zákona č. 455/1991 Sb., o živnostenském podnikání.</p></li><li><p>Účelem této Smlouvy je úprava podmínek, za kterých Manažer poskytuje Franšízantovi odbornou pomoc a metodické vedení k efektivnímu chodu Provozovny.</p></li></ol><h2>2. Odpovědnost a postavení Franšízanta</h2><ol><li><p>Franšízant nese plnou a výhradní odpovědnost za provoz Provozovny, zejména za:</p><ol><li><p>ekonomické výsledky (tržby, náklady, hospodářský výsledek),</p></li><li><p>pracovněprávní vztahy se zaměstnanci (dále jen „<strong>Zaměstnanci</strong>“),</p></li><li><p>zajištění zásobování zbožím a spotřebním materiálem,</p></li><li><p>dodržování veškerých právních, hygienických a bezpečnostních předpisů.</p></li></ol></li><li><p>Veškeré tržby plynoucí z provozu Provozovny náleží Franšízantovi, veškeré provozní náklady hradí Franšízant ze svých prostředků. Povinnost Franšízanta hradit franšízingový poplatek se řídí samostatnou franšízingovou smlouvou.</p></li><li><p>Manažer není spoluprovozovatelem Provozovny, statutárním orgánem ani osobou plnící závazky Franšízanta vůči třetím osobám ve smyslu § 1935 a § 2914 OZ. Doporučení Manažera jsou Franšízantem realizována pouze se souhlasem a na odpovědnost Franšízanta.</p></li></ol><h2>3. Předmět spolupráce</h2><ol><li><p>Manažer se zavazuje poskytovat Franšízantovi službu spočívající v pomoci s řízením Provozovny (dále jen „<strong>Služba</strong>“), a to prostřednictvím pověřeného pracovníka (dále jen „<strong>Regionální manažer</strong>“).</p></li><li><p>Náplň činnosti Regionálního manažera zahrnuje zejména:</p><ol><li><p>pravidelné fyzické kontroly čistoty, technického stavu a vizuálních standardů Provozovny,</p></li><li><p>metodické vedení Franšízanta při dodržování standardů Konceptu a kvality zákaznického servisu, včetně poskytování zpětné vazby a návrhů k nápravě nedostatků,</p></li><li><p>edukaci Franšízanta v práci s interním systémem pro objednávání zboží a spotřebního materiálu a v interpretaci reportů tržeb a nákladů,</p></li><li><p>metodické vedení Franšízanta při řízení Zaměstnanců (nastavení směn, motivační a tréninkové plány) a při tvorbě procesů pro nakládání s hotovostí a uzávěrky,</p></li><li><p>doporučení k lokálnímu marketingu a asistenci při jeho implementaci,</p></li><li><p>účast na vybraných provozních poradách Franšízanta na jeho žádost,</p></li><li><p>předávání novinek a aktualizací know-how z franšízové sítě.</p></li></ol></li><li><p>Regionální manažer bude s Franšízantem v pravidelném kontaktu formou osobních návštěv v Provozovně, telefonických konzultací a elektronické komunikace.</p></li><li><p>Smluvní strany výslovně sjednávají, že podstatou spolupráce je edukace a podpora Franšízanta. Regionální manažer vykonává činnost v součinnosti s Franšízantem, nikoliv namísto něj.</p></li></ol><h2>4. Vedlejší náklady a doplňkové služby</h2><ol><li><p>Pokud Manažer na základě předchozí dohody s Franšízantem zajistí pro Franšízanta nad rámec běžné Služby jakékoli další služby, činnosti nebo dodávky materiálu třetích stran nezbytné pro provoz Provozovny, zavazuje se Franšízant uhradit veškeré s tím spojené náklady v plné výši. Tyto náklady budou Franšízantovi přefakturovány Manažerem nebo budou na základě dohody fakturovány třetí stranou přímo Franšízantovi.</p></li></ol><h2>5. Cena Služby a platební podmínky</h2><ol><li><p>Franšízant se zavazuje hradit za poskytování Služby měsíční paušální odměnu ve výši <strong>15 000 Kč</strong> bez DPH (dále jen „<strong>Odměna</strong>“). K Odměně bude připočteno DPH v sazbě dle platných právních předpisů.</p></li><li><p>Odměna je splatná na základě daňového dokladu (faktury) vystaveného Manažerem nejpozději <strong>15. dne</strong> kalendářního měsíce následujícího po měsíci, za který se Odměna účtuje, se splatností minimálně 14 dnů. Faktura bude vystavena v měně CZK, EUR nebo PLN, a to dle vhodnosti podle typu lokace a umístění Provozovny. Měnu fakturace určí Manažer písemným oznámením Franšízantovi. Není-li určeno jinak, je výchozí měnou fakturace CZK.</p></li><li><p>Odměna je splatná bez ohledu na výši tržeb Provozovny v daném měsíci. Případná provozní ztráta Provozovny nemá vliv na výši Odměny. Smluvní strany výslovně potvrzují, že v případě provozní ztráty nese veškeré podnikatelské riziko spojené s provozem Provozovny Franšízant.</p></li><li><p>Manažer je oprávněn vždy jednou za kalendářní rok jednostranně zvýšit Odměnu o procentní přírůstek průměrného ročního indexu spotřebitelských cen za předchozí kalendářní rok, vyhlášený Českým statistickým úřadem. Takto zvýšená Odměna náleží Manažerovi zpětně od 1. ledna kalendářního roku, v němž Český statistický úřad tento údaj zveřejnil.</p></li><li><p>Pro případ prodlení Franšízanta s úhradou Odměny se Franšízant zavazuje platit Manažerovi od prvního dne prodlení úroky z prodlení ve výši <strong>0,1 %</strong> z dlužné částky za každý započatý den prodlení.</p></li></ol><h2>6. Trvání a ukončení Smlouvy</h2><ol><li><p>Tato Smlouva se uzavírá na dobu neurčitou.</p></li><li><p>Franšízant je oprávněn tuto Smlouvu vypovědět kdykoli i bez uvedení důvodu. Smlouva v takovém případě končí k poslednímu dni kalendářního měsíce, ve kterém byla písemná výpověď doručena Manažerovi.</p></li><li><p>Manažer je oprávněn tuto Smlouvu vypovědět v případě, že je Franšízant v prodlení s úhradou Odměny a tuto Odměnu neuhradí ani do 7 dnů ode dne, kdy byl k její úhradě Manažerem písemně vyzván. Smlouva v takovém případě končí k poslednímu dni kalendářního měsíce, ve kterém byla písemná výpověď doručena Franšízantovi.</p></li></ol><h2>7. Odpovědnost Manažera</h2><ol><li><p>Doporučení Manažera (Regionálního manažera) mají charakter best-practice metodiky. Franšízant je povinen je posoudit s přihlédnutím ke konkrétním podmínkám své Provozovny a v případě pochybností konzultovat s odborně způsobilou osobou. Manažer (Regionální manažer) neodpovídá za jakékoliv případné sankce či jiné veřejnoprávní postihy uložené Franšízantovi.</p></li><li><p>Smluvní strany sjednávají, že celková výše náhrady škody, za níž Manažer odpovídá Franšízantovi v souvislosti s touto Smlouvou (zejména dle § 2950 OZ), je za jeden incident omezena částkou odpovídající <strong>jednonásobku měsíční Odměny</strong>. Manažer dále neodpovídá za nepřímou škodu, ušlý zisk a následné škody.</p></li><li><p>Franšízant se zavazuje odškodnit Manažera za jakékoli sankce uložené veřejnoprávními orgány vůči Provozovně (zejména hygienické, daňové, pracovněprávní), ledaže by byly způsobeny prokázanou hrubou nedbalostí nebo úmyslem Manažera.</p></li></ol><h2>8. Závěrečná ustanovení</h2><ol><li><p>Tato Smlouva nabývá platnosti a účinnosti dnem jejího podpisu oběma Smluvními stranami.</p></li><li><p>Pro vyloučení všech pochybností Smluvní strany výslovně potvrzují, že jsou podnikateli, uzavírají tuto Smlouvu při svém podnikání, a na tuto Smlouvu se neuplatní ustanovení § 1793 OZ. Tato Smlouva nezakládá společnost ve smyslu § 2716 a násl. OZ ani tiché společenství dle § 2747 a násl. OZ.</p></li><li><p>Manažer je oprávněn tuto Smlouvu i bez souhlasu Franšízanta zčásti či zcela postoupit, přičemž postoupením se osvobozuje od svých povinností v rozsahu postoupení; Smluvní strany výslovně vylučují aplikaci § 1899 OZ.</p></li><li><p>Tuto Smlouvu lze měnit a doplňovat pouze písemnou formou vzestupně číslovaných dodatků podepsaných oběma Smluvními stranami.</p></li><li><p>Je-li některé ustanovení této Smlouvy neplatné nebo neúčinné, ostatní zůstávají platná. Smluvní strany se zavazují nahradit takové ustanovení novým, které nejlépe odpovídá původnímu účelu.</p></li></ol><h2>Podpisy</h2><p>V {{place}} dne {{contractDate}}.</p><p>&nbsp;</p><p>__________________________<br><strong>{{providerStatutory1Name}}</strong><br>{{providerStatutory1Role}}<br>za Manažera: {{providerName}}</p><p>&nbsp;</p><p>V _________ dne ______________ .</p><p>&nbsp;</p><p>__________________________<br><strong>{{clientSignerName}}</strong><br>{{clientSignerRole}}<br>za Franšízanta: {{clientName}}</p>`;
}

